import{_ as e,c as t,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"고급 기능: 서식 원리 | opencode-md-table-formatter","description":"opencode-md-table-formatter의 서식 원리를 심층적으로 이해하세요. 숨김 모드, 표 규격 및 정렬 방식을 마스터하고 플러그인 작동 원리를 완전히 파악하세요.","frontmatter":{"title":"고급 기능: 서식 원리 | opencode-md-table-formatter","subtitle":"고급 기능: 서식 원리","sidebarTitle":"작동 원리 이해","order":2,"description":"opencode-md-table-formatter의 서식 원리를 심층적으로 이해하세요. 숨김 모드, 표 규격 및 정렬 방식을 마스터하고 플러그인 작동 원리를 완전히 파악하세요.","prerequisite":["start-getting-started","start-features"],"tags":["고급","원리","규격"]},"headers":[],"relativePath":"ko/franlol/opencode-md-table-formatter/advanced/index.md","filePath":"ko/franlol/opencode-md-table-formatter/advanced/index.md"}'),l={name:"ko/franlol/opencode-md-table-formatter/advanced/index.md"};function i(n,a,s,d,c,h){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="고급-기능-markdown-표-서식의-기술적-세부사항-심층-이해" tabindex="-1">고급 기능: Markdown 표 서식의 기술적 세부사항 심층 이해 <a class="header-anchor" href="#고급-기능-markdown-표-서식의-기술적-세부사항-심층-이해" aria-label="Permalink to &quot;고급 기능: Markdown 표 서식의 기술적 세부사항 심층 이해&quot;">​</a></h1><h2 id="섹션-개요" tabindex="-1">섹션 개요 <a class="header-anchor" href="#섹션-개요" aria-label="Permalink to &quot;섹션 개요&quot;">​</a></h2><p>이 섹션에서는 Markdown 표 서식의 기술적 세부사항을 심층적으로 다룹니다. OpenCode 숨김 모드의 작동 원리, 유효한 표의 구조 규격, 정렬 방식에 대한 상세 설명을 포함합니다. 이 내용을 학습하면 플러그인이 표 서식을 처리하는 방법과 일반적인 오류를 방지하는 방법을 완전히 이해할 수 있습니다.</p><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><p>이 섹션의 내용은 다음 순서로 학습하는 것을 권장합니다:</p><div class="info custom-block"><p class="custom-block-title">학습 경로</p><ol><li><strong>숨김 모드 원리</strong> → OpenCode의 숨김 모드를 특별하게 처리해야 하는 이유 이해</li><li><strong>표 규격</strong> → 올바르게 서식화될 수 있는 표의 조건 마스터</li><li><strong>정렬 방식 상세</strong> → 표의 정렬과 미적 품질을 제어하는 방법 학습</li></ol></div><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><p>이 섹션을 시작하기 전에 다음 사항을 확인하세요:</p><ul><li>[x] <a href="./../start/getting-started/">1분 빠르게 시작</a>을 완료하고 플러그인을 성공적으로 설치 및 구성했는지 확인</li><li>[x] <a href="./../start/features/">기능 개요</a>를 읽고 플러그인의 기본 기능을 이해했는지 확인</li></ul><div class="warning custom-block"><p class="custom-block-title">중요 알림</p><p>아직 기초 학습을 완료하지 않았다면 <a href="./../start/getting-started/">빠르게 시작</a>로 돌아가서 시작하는 것을 권장합니다.</p></div><h2 id="섹션-탐색" tabindex="-1">섹션 탐색 <a class="header-anchor" href="#섹션-탐색" aria-label="Permalink to &quot;섹션 탐색&quot;">​</a></h2><h3 id="숨김-모드-원리" tabindex="-1"><a href="./concealment-mode/">숨김 모드 원리</a> <a class="header-anchor" href="#숨김-모드-원리" aria-label="Permalink to &quot;[숨김 모드 원리](./concealment-mode/)&quot;">​</a></h3><p>OpenCode 숨김 모드의 작동 원리와 플러그인이 표시 너비를 올바르게 계산하는 방법을 이해합니다. 다음 내용을 학습합니다:</p><ul><li>숨김 모드란 무엇이며 특별한 처리가 필요한 이유</li><li>Markdown 기호 제거 알고리즘이 작동하는 방식</li><li>너비 계산에서 <code>Bun.stringWidth()</code>의 역할</li></ul><p><strong>예상 소요 시간</strong>: 8분 | <strong>난이도</strong>: 중간 | <strong>전제 조건</strong>: 기능 개요</p><hr><h3 id="표-규격" tabindex="-1"><a href="./table-spec/">표 규격</a> <a class="header-anchor" href="#표-규격" aria-label="Permalink to &quot;[표 규격](./table-spec/)&quot;">​</a></h3><p>유효한 Markdown 표의 구조 요구사항을 마스터하고 &quot;유효하지 않은 표&quot; 오류를 방지합니다. 다음 내용을 학습합니다:</p><ul><li>어떤 표 구조가 유효한지</li><li>구분 행의 역할과 서식 요구사항</li><li>열 수 일관성 검사의 원리</li><li>표 구조 문제를 빠르게 식별하는 방법</li></ul><p><strong>예상 소요 시간</strong>: 6분 | <strong>난이도</strong>: 입문 | <strong>전제 조건</strong>: 숨김 모드 원리</p><hr><h3 id="정렬-방식-상세" tabindex="-1"><a href="./alignment/">정렬 방식 상세</a> <a class="header-anchor" href="#정렬-방식-상세" aria-label="Permalink to &quot;[정렬 방식 상세](./alignment/)&quot;">​</a></h3><p>세 가지 정렬 방식의 구문과 효과를 마스터하여 표를 더 아름답게 만듭니다. 다음 내용을 학습합니다:</p><ul><li>왼쪽 정렬, 중앙 정렬, 오른쪽 정렬의 구문</li><li>구분 행에서 정렬 방식을 지정하는 방법</li><li>셀 내용 채우기 알고리즘</li><li>정렬과 표시 너비의 관계</li></ul><p><strong>예상 소요 시간</strong>: 10분 | <strong>난이도</strong>: 중간 | <strong>전제 조건</strong>: 표 규격</p><hr><h2 id="섹션-요약" tabindex="-1">섹션 요약 <a class="header-anchor" href="#섹션-요약" aria-label="Permalink to &quot;섹션 요약&quot;">​</a></h2><p>이 섹션을 완료하면 다음을 수행할 수 있습니다:</p><ul><li>✅ OpenCode 숨김 모드의 작동 원리 이해</li><li>✅ 유효한 표의 구조 요구사항 마스터</li><li>✅ 유효하지 않은 표 식별 및 수정</li><li>✅ 세 가지 정렬 방식 능숙하게 사용</li><li>✅ 플러그인 내부의 기술적 구현 세부사항 이해</li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 섹션을 완료한 후 다음을 수행할 수 있습니다:</p><ol><li><strong>실제 문제 해결</strong> → <a href="./../../faq/troubleshooting/">일반적인 문제</a>를 학습하여 문제를 빠르게 찾고 해결</li><li><strong>기술적 경계 이해</strong> → <a href="./../../appendix/limitations/">알려진 제한 사항</a>을 읽고 플러그인의 적용 가능한 시나리오 이해</li><li><strong>구현 심층 이해</strong> → <a href="./../../appendix/tech-details/">기술적 세부사항</a>를 확인하여 캐싱 메커니즘과 성능 최적화 이해</li></ol><hr><div class="tip custom-block"><p class="custom-block-title">실용적인 제안</p><p>표 서식 문제를 빠르게 해결하고 싶다면 이 섹션의 <a href="./table-spec/">표 규격</a>을 먼저 읽어보세요. 가장 일반적인 유효하지 않은 표 사례가 포함되어 있습니다.</p></div>',34)])])}const m=e(l,[["render",i]]);export{u as __pageData,m as default};
